# special_chapter.py
def get_special_chapter(start_article):
    thai_nums = {'0': '๐', '1': '๑', '2': '๒', '3': '๓', '4': '๔', '5': '๕', '6': '๖', '7': '๗', '8': '๘', '9': '๙'}
    def to_thai(n):
        return ''.join(thai_nums[d] for d in str(n))
        
    text = [
        "\n\n" + "="*50,
        "หมวดพิเศษ : อำนาจสูงสุดพิทักษ์ประชาชน (The Supreme People's Power)",
        "="*50 + "\n",
        f"มาตรา {to_thai(start_article)}  สภาประชาชนสูงสุด (Supreme Citizen Assembly): ให้มีสภาประชาชนสูงสุดประกอบด้วยประชาชนที่ได้จากการสุ่มเลือก (Sortition) จำนวนห้าร้อยคน หมุนเวียนวาระละหนึ่งปี มีอำนาจในฐานะตัวแทนปวงชนชาวไทยโดยตรง สภานี้มีอำนาจยับยั้ง (Veto) กฎหมาย มติคณะรัฐมนตรี หรือคำพิพากษาศาลฎีกาที่ขัดต่อประโยชน์สาธารณะได้",
        " ",
        f"มาตรา {to_thai(start_article+1)}  ระบบประชาธิปไตยทางตรงดิจิทัล: รัฐต้องจัดตั้งระบบออกเสียงผ่านแอปพลิเคชันที่มีความปลอดภัยสูงสุด ให้ประชาชนทุกคนสามารถเสนอกฎหมายและร่วมโหวตผ่านโทรศัพท์มือถือได้ หากกฎหมายใดที่ประชาชนโหวตเห็นชอบเกินกึ่งหนึ่งของผู้มีสิทธิเลือกตั้งทั้งประเทศ ให้มีผลบังคับใช้เป็นกฎหมายทันทีโดยไม่ต้องผ่านรัฐสภา",
        " ",
        f"มาตรา {to_thai(start_article+2)}  การถอดถอนข้าราชการระดับสูง: สิทธิในการถอดถอน (Recall) มิได้จำกัดเพียงแค่นักการเมือง ประชาชนจำนวนหนึ่งหมื่นคนสามารถเข้าชื่อเพื่อจัดให้มีการลงประชามติถอดถอน ผู้พิพากษา อัยการสูงสุด ผบ.ตร. ผบ.ทบ. หรือข้าราชการระดับปลัดกระทรวง ได้ทุกเมื่อหากพบว่าทุจริตหรือปฏิบัติหน้าที่โดยมิชอบ",
        " ",
        f"มาตรา {to_thai(start_article+3)}  รายได้พื้นฐานถ้วนหน้า (Universal Basic Income - UBI): รัฐต้องประกันรายได้พื้นฐานให้แก่ประชาชนชาวไทยทุกคนตั้งแต่เกิดจนตาย ในอัตราไม่ต่ำกว่าเส้นความยากจน โดยห้ามนำข้ออ้างด้านงบประมาณมาลิดรอนสิทธินี้",
        " ",
        f"มาตรา {to_thai(start_article+4)}  สิทธิการเข้าควบคุมกิจการ (Worker's Control): ในกรณีที่กลุ่มทุนขนาดใหญ่หรือองค์กรเอกชนกระทำการเอาเปรียบประชาชนอย่างร้ายแรง สหภาพแรงงานและสมาคมผู้บริโภคมีสิทธิเข้าควบคุมและยึดกิจการนั้นมาดำเนินการในรูปแบบสหกรณ์ที่ประชาชนเป็นเจ้าของร่วมกันได้",
        " ",
        f"มาตรา {to_thai(start_article+5)}  กองทุนต่อต้านการทุจริตภาคประชาชน: ทรัพย์สินที่ยึดได้จากนักการเมืองและข้าราชการที่ทุจริตทั้งหมด ต้องถูกนำเข้ากองทุนนี้ และให้สภาประชาชนสูงสุดเป็นผู้จัดสรรเพื่อนำไปใช้เยียวยาผู้ได้รับผลกระทบ หรือลงทุนในโครงสร้างพื้นฐานของชุมชนท้องถิ่น",
        " ",
        f"มาตรา {to_thai(start_article+6)}  บทสรุปแห่งความศักดิ์สิทธิ์: รัฐธรรมนูญฉบับนี้ร่างขึ้นจากเจตจำนงของประชาชน การตีความเพื่อลดทอนสิทธิและอำนาจของประชาชนตามรัฐธรรมนูญนี้ จะกระทำมิได้โดยเด็ดขาด องค์กรหรือบุคคลใดฝ่าฝืน ให้ถือว่าเป็นการทรยศต่อชาติและประชาชน",
        " ",
        f"มาตรา {to_thai(start_article+7)}  ข้อห้ามในการยกเลิกรัฐธรรมนูญและความผิดฐานกบฏแผ่นดิน: รัฐธรรมนูญฉบับนี้ไม่สามารถยกเลิกได้หากไม่ผ่านความเห็นชอบของประชาชนผ่านการออกเสียงประชามติ ไม่มีอำนาจหรือคณะบุคคลใดๆ ที่จะมีอำนาจยกเลิกรัฐธรรมนูญนี้ได้ ยกเว้นอำนาจของประชาชนผ่านการออกเสียงประชามติเท่านั้น ในกรณีที่คณะรัฐประหารหรือคณะบุคคลใดประกาศยกเลิกหรือลบล้างรัฐธรรมนูญนี้ ให้ถือว่าสมาชิกคณะบุคคลหรือคณะรัฐประหารดังกล่าวทั้งหมดมีความผิดฐานเป็นกบฏแผ่นดิน มีโทษสูงสุดโดยไม่มีอายุความ และห้ามมิให้มีการนิรโทษกรรมแก่คณะบุคคลดังกล่าวไม่ว่าด้วยวิธีการหรือทางใดๆ ก็ตาม"
    ]
    return "\n".join(text)

if __name__ == "__main__":
    print(get_special_chapter(1129))
